pub fn adaptive_sort<T: Ord + Clone>(arr: &mut [T]) {
    let n = arr.len();
    if n < 24 {
        for i in 1..n {
            let mut j = i;
            while j > 0 && arr[j - 1] > arr[j] { arr.swap(j, j - 1); j -= 1; }
        }
        return;
    }
    if arr.windows(2).all(|w| w[0] <= w[1]) { return; }
    let m = n / 2;
    if arr[m] < arr[0] { arr.swap(0, m); }
    if arr[n - 1] < arr[0] { arr.swap(0, n - 1); }
    if arr[n - 1] < arr[m] { arr.swap(m, n - 1); }
    let (p, mut l, mut i, mut g) = (arr[m].clone(), 0, 0, n);
    while i < g {
        match arr[i].cmp(&p) {
            Ordering::Less => { arr.swap(i, l); l += 1; i += 1; }
            Ordering::Greater => { g -= 1; arr.swap(i, g); }
            Ordering::Equal => i += 1,
        }
    }
    adaptive_sort(&mut arr[..l]);
    adaptive_sort(&mut arr[g..]);
}
// EVOLVE-BLOCK-END

